```typescript
function solve(code: string[], businessLine: string[], isActive: boolean[]): string[] {
    const allowedBusiness = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const businessMap = {
        "electronics": 0,
        "grocery": 1,
        "pharmacy": 2,
        "restaurant": 3
    };
    const validCoupons: { businessLine: string; code: string }[] = [];

    for (let i = 0; i < code.length; i++) {
        const c = code[i];
        const bl = businessLine[i];
        const active = isActive[i];

        if (c.length === 0) continue;
        if (!/^[a-zA-Z0-9_]+$/.test(c)) continue;
        if (!allowedBusiness.has(bl)) continue;
        if (!active) continue;

        validCoupons.push({ businessLine: bl, code: c });
    }

    validCoupons.sort((a, b) => {
        const aOrder = businessMap[a.businessLine];
        const bOrder = businessMap[b.businessLine];
        if (aOrder !== bOrder) {
            return aOrder - bOrder;
        }
        return a.code.localeCompare(b.code);
    });

    return validCoupons.map(c => c.code);
}
```

